package policy

import (
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	corev1 "k8s.io/api/core/v1"
)

// Config holds policy configuration flags.
type Config struct {
	DenyPrivileged       bool `json:"denyPrivileged" yaml:"denyPrivileged"`
	DenyHostNetwork      bool `json:"denyHostNetwork" yaml:"denyHostNetwork"`
	RequireResourceLimits bool `json:"requireResourceLimits" yaml:"requireResourceLimits"`
	RequireSecurityContext bool `json:"requireSecurityContext" yaml:"requireSecurityContext"`
}

// DefaultConfig returns a Config with all policies enabled.
func DefaultConfig() *Config {
	return &Config{
		DenyPrivileged:        true,
		DenyHostNetwork:       true,
		RequireResourceLimits: true,
		RequireSecurityContext: true,
	}
}

// AdmissionRequest wraps the relevant fields from a Kubernetes admission request.
type AdmissionRequest struct {
	UID       string
	Name      string
	Namespace string
	Pod       *corev1.PodSpec
	Metadata  *metav1.ObjectMeta
}

// ValidationResult holds the outcome of a policy validation.
type ValidationResult struct {
	Allowed  bool
	Reason   string
	Warnings []string
}

package policy

import (
	"encoding/json"
	"os"
)

// LoadConfig reads the policy configuration from a JSON file.
func LoadConfig(path string) (*Config, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return DefaultConfig(), nil // Fall back to defaults if no config file
	}
	var cfg Config
	if err := json.Unmarshal(data, &cfg); err != nil {
		return nil, err
	}
	return &cfg, nil
}

package main

import (
	"fmt"
	"log"
	"net/http"
	"os"
)

const (
	defaultPort    = "8443"
	defaultCertDir = "/etc/webhook/certs"
)

func main() {
	port := os.Getenv("WEBHOOK_PORT")
	if port == "" {
		port = defaultPort
	}

	certDir := os.Getenv("CERT_DIR")
	if certDir == "" {
		certDir = defaultCertDir
	}

	// TODO: Initialize validator and set up admission webhook handler
	log.Printf("Starting Terravault admission webhook on port %s\n", port)

	mux := http.NewServeMux()
	// TODO: Register /validate handler

	certFile := fmt.Sprintf("%s/tls.crt", certDir)
	keyFile := fmt.Sprintf("%s/tls.key", certDir)

	server := &http.Server{
		Addr:    fmt.Sprintf(":%s", port),
		Handler: mux,
	}

	log.Fatal(server.ListenAndServeTLS(certFile, keyFile))
}

