package policy

import (
	"fmt"
)

// Validator handles pod security policy validation.
type Validator struct {
	config *Config
}

// NewValidator creates a new policy validator with the given configuration.
func NewValidator(cfg *Config) *Validator {
	return &Validator{config: cfg}
}

// Validate performs policy validation on an admission request.
// Returns allowed (bool), reason (string), error.
func (v *Validator) Validate(req *AdmissionRequest) (*ValidationResult, error) {
	if req == nil || req.Pod == nil || req.Metadata == nil {
		return &ValidationResult{
			Allowed: false,
			Reason:  "invalid admission request: missing pod spec or metadata",
		}, nil
	}

	var denied []string

	// Policy 1: No privileged containers
	if v.config.DenyPrivileged {
		if reason := checkPrivileged(req.Pod); reason != "" {
			denied = append(denied, reason)
		}
	}

	// Policy 2: No host network
	if v.config.DenyHostNetwork {
		if reason := checkHostNetwork(req); reason != "" {
			denied = append(denied, reason)
		}
	}

	// Policy 3: Required resource limits
	if v.config.RequireResourceLimits {
		for _, reason := range checkResourceLimits(req.Pod) {
			denied = append(denied, reason)
		}
	}

	// Policy 4: Mandatory security context
	if v.config.RequireSecurityContext {
		for _, reason := range checkSecurityContext(req.Pod) {
			denied = append(denied, reason)
		}
	}

	if len(denied) > 0 {
		return &ValidationResult{
			Allowed: false,
			Reason:  "admission denied: " + formatDenial(denied[0], ""),
			Warnings: nil,
		}, nil
	}

	return &ValidationResult{
		Allowed: true,
		Reason:  "pod passed all security policy checks",
	}, nil
}

// checkPrivileged returns a denial reason if any container (or init container)
// runs in privileged mode.
func checkPrivileged(podSpec *AdmissionRequest) string {
	for _, container := range podSpec.Pod.Containers {
		if sc := container.SecurityContext; sc != nil && sc.Privileged != nil && *sc.Privileged {
			return formatDenial("no-privileged", fmt.Sprintf("container %q has privileged: true", container.Name))
		}
	}
	for _, container := range podSpec.Pod.InitContainers {
		if sc := container.SecurityContext; sc != nil && sc.Privileged != nil && *sc.Privileged {
			return formatDenial("no-privileged", fmt.Sprintf("init container %q has privileged: true", container.Name))
		}
	}
	return ""
}

// checkHostNetwork returns a denial reason if the pod uses host network.
func checkHostNetwork(req *AdmissionRequest) string {
	if req.Pod.HostNetwork {
		return formatDenial("no-host-network",
			fmt.Sprintf("pod %q uses hostNetwork: true", req.Metadata.Name))
	}
	return ""
}

// checkResourceLimits returns a list of denial reasons for containers that
// are missing required CPU or memory limits.
func checkResourceLimits(podSpec *AdmissionRequest) []string {
	var reasons []string

	for _, container := range podSpec.Pod.Containers {
		reasons = checkContainerLimits(container)
	}
	for _, container := range podSpec.Pod.InitContainers {
		reasons = append(reasons, checkContainerLimits(container)...)
	}
	return reasons
}

func checkContainerLimits(container corev1.Container) []string {
	var reasons []string
	if container.Resources.Limits == nil {
		reasons = append(reasons, formatDenial("resource-limits",
			fmt.Sprintf("container %q has no resource limits set", container.Name)))
		return reasons
	}
	if _, hasCPU := container.Resources.Limits["cpu"]; !hasCPU {
		reasons = append(reasons, formatDenial("resource-limits",
			fmt.Sprintf("container %q has no CPU limit", container.Name)))
	}
	if _, hasMem := container.Resources.Limits["memory"]; !hasMem {
		reasons = append(reasons, formatDenial("resource-limits",
			fmt.Sprintf("container %q has no memory limit", container.Name)))
	}
	return reasons
}

// checkSecurityContext returns a list of denial reasons for containers that
// do not enforce runAsNonRoot and readOnlyRootFilesystem.
func checkSecurityContext(podSpec *AdmissionRequest) []string {
	var reasons []string

	for _, container := range podSpec.Pod.Containers {
		reasons = append(reasons, checkContainerSecurityContext(container)...)
	}
	for _, container := range podSpec.Pod.InitContainers {
		reasons = append(reasons, checkContainerSecurityContext(container)...)
	}
	return reasons
}

func checkContainerSecurityContext(container corev1.Container) []string {
	var reasons []string
	sc := container.SecurityContext
	if sc == nil {
		reasons = append(reasons, formatDenial("security-context",
			fmt.Sprintf("container %q has no securityContext set", container.Name)))
		return reasons
	}
	if sc.RunAsNonRoot == nil || !*sc.RunAsNonRoot {
		reasons = append(reasons, formatDenial("security-context",
			fmt.Sprintf("container %q does not enforce runAsNonRoot: true", container.Name)))
	}
	if sc.ReadOnlyRootFilesystem == nil || !*sc.ReadOnlyRootFilesystem {
		reasons = append(reasons, formatDenial("security-context",
			fmt.Sprintf("container %q does not enforce readOnlyRootFilesystem: true", container.Name)))
	}
	return reasons
}

func formatDenial(policy string, detail string) string {
	return fmt.Sprintf("policy violation [%s]: %s", policy, detail)
}

