// validateHandler handles admission review requests.
func validateHandler(w http.ResponseWriter, r *http.Request, v *policy.Validator) {
	if r.Method != http.MethodPost {
		w.WriteHeader(http.StatusMethodNotAllowed)
		return
	}

	var admissionReview metav1.AdmissionReview
	if err := json.NewDecoder(r.Body).Decode(&admissionReview); err != nil {
		w.WriteHeader(http.StatusBadRequest)
		fmt.Fprintf(w, "failed to decode admission review: %v", err)
		return
	}

	// Extract the admission request from the review
	request := admissionReview.Request
	if request == nil {
		w.WriteHeader(http.StatusBadRequest)
		fmt.Fprintf(w, "admission review request is nil")
		return
	}

	// Parse the pod spec and metadata from the request object
	podSpec, metadata, err := parseAdmissionRequest(request)
	if err != nil {
		w.WriteHeader(http.StatusBadRequest)
		fmt.Fprintf(w, "failed to parse request: %v", err)
		return
	}

	// Build our internal admission request
	admReq := &policy.AdmissionRequest{
		UID:       request.UID,
		Name:      metadata.Name,
		Namespace: request.Namespace,
		Pod:       podSpec,
		Metadata:  metadata,
	}

	// Run validation
	result, err := v.Validate(admReq)
	if err != nil {
		w.WriteHeader(http.StatusInternalServerError)
		fmt.Fprintf(w, "validation failed: %v", err)
		return
	}

	// Build the admission response
	response := &metav1.AdmissionResponse{
		UID: request.UID,
		Allowed: result.Allowed,
	}

	if !result.Allowed {
		response.Result = &metav1.Status{
			Message: result.Reason,
			Code:    http.StatusForbidden,
		}
	}

	// Build the admission review response
	admissionReview := metav1.AdmissionReview{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "admission.k8s.io/v1",
			Kind:       "AdmissionReview",
		},
		Response: response,
	}

	w.Header().Set("Content-Type", "application/json")
	if err := json.NewEncoder(w).Encode(admissionReview); err != nil {
		log.Printf("failed to encode response: %v", err)
	}
}

// parseAdmissionRequest extracts the pod spec and metadata from an admission request.
func parseAdmissionRequest(request *metav1.AdmissionRequest) (*corev1.PodSpec, *metav1.ObjectMeta, error) {
	if request.Object.Raw == nil {
		return nil, nil, fmt.Errorf("no object data in request")
	}

	var pod corev1.Pod
	if err := json.Unmarshal(request.Object.Raw, &pod); err != nil {
		return nil, nil, fmt.Errorf("failed to unmarshal pod: %v", err)
	}

	return &pod.Spec, &pod.ObjectMeta, nil
}

