package policy

import (
	"fmt"

	corev1 "k8s.io/api/core/v1"
)

// Validator handles pod security policy validation.
type Validator struct {
	config *Config
}

// NewValidator creates a new policy validator with the given configuration.
func NewValidator(cfg *Config) *Validator {
	return &Validator{config: cfg}
}

// Validate performs policy validation on an admission request.
// Returns allowed (bool), reason (string), error.
func (v *Validator) Validate(req *AdmissionRequest) (*ValidationResult, error) {
	if req == nil || req.Pod == nil || req.Metadata == nil {
		return &ValidationResult{
			Allowed: false,
			Reason:  "invalid admission request: missing pod spec or metadata",
		}, nil
	}

	var denied []string

	// Policy 1: No privileged containers
	if v.config.DenyPrivileged {
		if reason := checkPrivileged(req); reason != "" {
			denied = append(denied, reason)
		}
	}

	// Policy 2: No host network
	if v.config.DenyHostNetwork {
		if reason := checkHostNetwork(req); reason != "" {
			denied = append(denied, reason)
		}
	}

	// Policy 3: Required resource limits
	if v.config.RequireResourceLimits {
		for _, reason := range checkResourceLimits(req.Pod) {
			denied = append(denied, reason)
		}
	}

	// Policy 4: Mandatory security context
	if v.config.RequireSecurityContext {
		for _, reason := range checkSecurityContext(req.Pod) {
			denied = append(denied, reason)
		}
	}

	if len(denied) > 0 {
		return &ValidationResult{
			Allowed: false,
			Reason:  "admission denied: " + denied[0],
		}, nil
	}

	return &ValidationResult{
		Allowed: true,
		Reason:  "pod passed all security policy checks",
	}, nil
}

// checkPrivileged returns a denial reason if any container runs in privileged mode.
func checkPrivileged(req *AdmissionRequest) string {
	for _, c := range req.Pod.Containers {
		if c.SecurityContext != nil && c.SecurityContext.Privileged != nil && *c.SecurityContext.Privileged {
			return formatDenial("no-privileged", fmt.Sprintf("container %q has privileged: true", c.Name))
		}
	}
	for _, c := range req.Pod.InitContainers {
		if c.SecurityContext != nil && c.SecurityContext.Privileged != nil && *c.SecurityContext.Privileged {
			return formatDenial("no-privileged", fmt.Sprintf("init container %q has privileged: true", c.Name))
		}
	}
	return ""
}

// checkHostNetwork returns a denial reason if the pod uses host network.
func checkHostNetwork(req *AdmissionRequest) string {
	if req.Pod.HostNetwork {
		return formatDenial("no-host-network", fmt.Sprintf("pod %q uses hostNetwork: true", req.Metadata.Name))
	}
	return ""
}

// checkResourceLimits returns a list of denial reasons for containers missing limits.
func checkResourceLimits(podSpec *corev1.PodSpec) []string {
	var reasons []string
	for _, c := range podSpec.Containers {
		reasons = append(reasons, checkContainerLimits(c)...)
	}
	for _, c := range podSpec.InitContainers {
		reasons = append(reasons, checkContainerLimits(c)...)
	}
	return reasons
}

func checkContainerLimits(c corev1.Container) []string {
	var reasons []string
	if c.Resources.Limits == nil {
		reasons = append(reasons, formatDenial("resource-limits", fmt.Sprintf("container %q has no resource limits set", c.Name)))
		return reasons
	}
	if _, hasCPU := c.Resources.Limits["cpu"]; !hasCPU {
		reasons = append(reasons, formatDenial("resource-limits", fmt.Sprintf("container %q has no CPU limit", c.Name)))
	}
	if _, hasMem := c.Resources.Limits["memory"]; !hasMem {
		reasons = append(reasons, formatDenial("resource-limits", fmt.Sprintf("container %q has no memory limit", c.Name)))
	}
	return reasons
}

// checkSecurityContext returns denial reasons for containers missing required security settings.
func checkSecurityContext(podSpec *corev1.PodSpec) []string {
	var reasons []string
	for _, c := range podSpec.Containers {
		reasons = append(reasons, checkContainerSecurityContext(c)...)
	}
	for _, c := range podSpec.InitContainers {
		reasons = append(reasons, checkContainerSecurityContext(c)...)
	}
	return reasons
}

func checkContainerSecurityContext(c corev1.Container) []string {
	var reasons []string
	if c.SecurityContext == nil {
		reasons = append(reasons, formatDenial("security-context", fmt.Sprintf("container %q has no securityContext set", c.Name)))
		return reasons
	}
	if c.SecurityContext.RunAsNonRoot == nil || !*c.SecurityContext.RunAsNonRoot {
		reasons = append(reasons, formatDenial("security-context", fmt.Sprintf("container %q does not enforce runAsNonRoot: true", c.Name)))
	}
	if c.SecurityContext.ReadOnlyRootFilesystem == nil || !*c.SecurityContext.ReadOnlyRootFilesystem {
		reasons = append(reasons, formatDenial("security-context", fmt.Sprintf("container %q does not enforce readOnlyRootFilesystem: true", c.Name)))
	}
	return reasons
}

func formatDenial(policy string, detail string) string {
	return fmt.Sprintf("policy violation [%s]: %s", policy, detail)
}

